  ('elementary-10ced7e2-moex-00541', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '修正法規時，如欲廢止或增加少數條文時，應為如何之處理？', '["不保留所廢條文之條次", "保留所廢條文之內容，且須註明「刪除」二字", "得將增加之條文，列在適當條文之後，冠以前條「之一」、「之二」等條次", "增加編或章時，不得冠以「之一」、「之二」等編或章次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00542', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依司法院憲法解釋意旨，下列何者為憲法中具有本質之重要性，即便修憲亦不可更動者？', '["雙首長制", "權力分立與制衡", "國家固有疆域", "修憲程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00543', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於憲法之共和原則，下列敘述何者錯誤？', '["國家元首應由人民直選產生", "國家元首應受到任期限制", "共和國不一定是民主國", "國家元首不能以世襲方式產生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00544', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '國立警察大學碩士班入學之招生簡章，限制有色盲者不得報考。依司法院憲法解釋意旨，該規定所 涉及之基本權，下列敘述何者最正確？', '["該規定對於憲法第21條保障人民受教育權造成限制", "該規定對於大學自治造成限制", "大法官採較嚴格審查標準予以審查", "該規定以生理特徵為分類標準，是違憲之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00545', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於總統制之敘述，何者最明顯有誤？', '["總統與國會分別有獨立的民意基礎", "總統對於國會通過之法案有否決權", "國會對內閣沒有質詢的權力", "內閣成員同時具有國會議員身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00546', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關民主，下列敘述何者錯誤？', '["公民投票是國民主權的展現，位階高於憲法", "在民主社會中，「保護少數」與「多數決」不可分離，而違憲審查是保護少數的一種制度設計", "民主政治的預設之一是主流意見會隨時代與環境而改變", "在普通、平等、直接、無記名的投票方法中，平等是指一人一票且票票等值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00547', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者不屬於「法律保留原則」之內涵？', '["行政行為或其他一切行政活動，均不得與法律相牴觸", "憲法要求特定事項須由立法機關以法律加以規定", "何種事項應以法律直接規範或得委由命令予以規定，視規範對象、內容或法益本身及其所受限制 之輕重而有不同", "有組織法之授權不等於即有作用法之授權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00548', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於聯邦國與單一國之選擇，下列敘述何者錯誤？', '["單一國之地方政府不具水平權力分立之機關", "兩者在國家統治權力分配上有所不同", "聯邦國之成員州或邦得有獨立之司法系統", "聯邦國之成員州或邦享有憲法保障之自主權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00549', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依行政執行法規定，行政執行，應以適當之方法為之，不得逾達成執行目的之必要限度。此為下列 何原則之實現？', '["法律保留原則", "明確性原則", "信賴保護原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
